      "industries.r1.minimum.v": "3 seter ยท 6 mรฅneder",
      "industries.r2.name": "Direkte kjรธp",
      "industries.r2.desc": "For sluttkjรธpere",
      "industries.r2.body1": "Per-leveranse-kjรธp direkte fra portalen. Kjรธperen laster opp prosjektdata, velger modul og leveransenivรฅ, og mottar utgangen i รธnsket format. Ingen lisens, ingen implementeringskostnader.",
      "industries.r2.body2": "Egnet for utviklere, lรฅngivere og kapitalforvaltere som kjรธper auto-nivรฅ-leveranser pรฅ forespรธrsel. Ingeniรธr-gjennomgรฅtt og attestert nivรฅ ogsรฅ tilgjengelig der det kreves.",
      "industries.r2.pricing.v": "Per leveranse",
      "industries.r2.onboarding.v": "Samme dag",
      "industries.r2.minimum.v": "รn leveranse",
      "industries.r3.name": "Partnerintegrasjon",
      "industries.r3.body2": "Egnet for storvolumsintegrasjoner og der plattformens utganger er input til en bredere arbeidsflyt.",
      "industries.r3.pricing.v": "Forhandlet ยท volum",
      "industries.r3.onboarding.v": "6โ12 uker",
      "industries.r3.minimum.v": "รrlig forpliktelse",
      "industries.insight.accent": "Den samme ingeniรธrfaglige nรธyaktigheten, uansett hvem som kjรธper.",
      "industries.cta.btn.open_portal": "รpne portalen",
      "industries.cta.row.licence.k": "Plattformlisens",
