      "industries.r1.minimum.v": "3 sรฆder ยท 6 mรฅneder",
      "industries.r2.name": "Direkte kรธb",
      "industries.r2.desc": "For slutkรธbere",
      "industries.r2.body1": "Per-leverance-kรธb direkte fra portalen. Kรธberen uploader projektinput, vรฆlger modul og leveranceniveau, og modtager udgangen i det foretrukne format. Ingen licens, ingen implementeringsomkostninger.",
      "industries.r2.body2": "Egnet til udviklere, lรฅngivere og kapitalforvaltere der kรธber auto-niveau-leverancer efter behov. Ingeniรธr-gennemgรฅet og attesterede niveauer ogsรฅ tilgรฆngelige hvor det krรฆves.",
      "industries.r2.pricing.v": "Per leverance",
      "industries.r2.onboarding.v": "Samme dag",
      "industries.r2.minimum.v": "รn leverance",
      "industries.r3.name": "Partnerintegration",
      "industries.r3.body2": "Egnet til storvolums-integrationer og hvor platformens udgange er input til en bredere arbejdsstrรธm.",
      "industries.r3.pricing.v": "Forhandlet ยท volumen",
      "industries.r3.onboarding.v": "6โ12 uger",
      "industries.r3.minimum.v": "รrlig forpligtelse",
      "industries.insight.accent": "Samme ingeniรธrmรฆssige stringens, uanset hvem der kรธber.",
      "industries.cta.btn.open_portal": "รbn portalen",
