      "ethics.toc.s07": "Klima, miljรธ og bรฆredygtighed",
      "ethics.toc.s08": "Due diligence (รbenhedsloven)",
      "ethics.toc.s09": "Fortrolighed og databeskyttelse",
      "ethics.toc.s10": "Professionelt ansvar i automatiseret ingeniรธrarbejde",
      "ethics.toc.s11": "Konkurrence og forretningsforbindelser",
