      "careers.pos.4.type": "Senior ยท Hybrid",
      "careers.pos.5.name": "Senior-Ingenieur ยท Tragwerk",
      "careers.pos.5.desc": "Senior Tragwerksplaner mit regulatorischer Autoritรคt zur Attestierung von Lieferungen. Leiten Sie die Entwicklung des Tragwerksmoduls โ Eurocode-1 bis Eurocode-9, BIM-Integration, IFC4-Modellverarbeitung. Tiefe BIM-native praktische Erfahrung erforderlich.",
      "careers.pos.5.meta": "Disziplin ยท Tragwerk",
      "careers.pos.5.type": "Senior ยท Hybrid",
